def flip_case(string: str) -> str:
    """ For a given string, flip lowercase characters to uppercase and uppercase to lowercase.
    >>> flip_case('Hello')
    'hELLO'
    """
    result = string
    for i in string:
        if 96 < ord(i) <= 122:
            result = result.replace(i, chr(ord(i) - 32))
        elif 64 < ord(i) <= 90:
            result = result.replace(i, chr(ord(i) + 32))
        else:
            pass

    return result

